const now = new Date();
const items = $input.all().map(i => i.json);

const MEMBER_MAP = {
  'Fernando Joel Bonilla Guerrero': { github: 'JoelBonillaG', initials: 'FG' },
  'Joel Bonilla': { github: 'JoelBonillaG', initials: 'FG' },
  'David Manjarres': { github: 'DRTX2', initials: 'DM' },
  'David Oswaldo Manjarres Quintero': { github: 'DRTX2', initials: 'DM' },
  'David Josue Barragan Pozo': { github: 'DavidJosueP2', initials: 'DP' },
  'David Josué Barragán Pozo': { github: 'DavidJosueP2', initials: 'DP' },
  'David Barragán Pozo': { github: 'DavidJosueP2', initials: 'DP' },
  'David Barragan Pozo': { github: 'DavidJosueP2', initials: 'DP' },
  'Josue Joel Garcia Abata': { github: 'JosueGarciaAbata', initials: 'JA' },
  'Josué Joel García Abata': { github: 'JosueGarciaAbata', initials: 'JA' },
  'Josué García Abata': { github: 'JosueGarciaAbata', initials: 'JA' },
  'Josue Garcia Abata': { github: 'JosueGarciaAbata', initials: 'JA' }
};

function resolveMember(fullName) {
  if (!fullName) return { github: null, initials: '??' };
  if (MEMBER_MAP[fullName]) return MEMBER_MAP[fullName];
  const norm = fullName.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  for (const [k, v] of Object.entries(MEMBER_MAP)) {
    if (k.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '') === norm) return v;
  }
  const parts = fullName.split(' ').filter(Boolean);
  const initials = (parts[0]?.[0] || '?') + (parts[parts.length - 1]?.[0] || '');
  return { github: null, initials: initials.toUpperCase() };
}

const backRepo = $node['Configuración'].json.GITHUB_REPO_BACKEND;
const frontRepo = $node['Configuración'].json.GITHUB_REPO_FRONTEND;

let cards = [], lists = [], members = [], historial = [], hitos = [], checklists = [];
let bRuns = [], fRuns = [];

items.forEach(d => {
  if (!d || typeof d !== 'object') return;
  if (d.workflow_runs !== undefined && Array.isArray(d.workflow_runs)) {
    const first = d.workflow_runs[0];
    const repoName = first?.repository?.name || first?.head_repository?.name || '';
    if (repoName === backRepo) bRuns = d.workflow_runs;
    else if (repoName === frontRepo) fRuns = d.workflow_runs;
    else if (!bRuns.length) bRuns = d.workflow_runs;
    else fRuns = d.workflow_runs;
    return;
  }
  if (d.idCard && Array.isArray(d.checkItems)) { checklists.push(d); return; }
  if (d.nombre && d.tipo && d.fecha_fin !== undefined) { hitos.push(d); return; }
  if (d.fecha_ejecucion !== undefined) { historial.push(d); return; }
  if (d.id && d.name && d.idList !== undefined && d.due !== undefined) { cards.push(d); return; }
  if (d.id && d.name && d.closed !== undefined && !d.idList) { lists.push(d); return; }
  if (d.id && (d.fullName || d.username) && !d.idList && !d.name) { members.push(d); return; }
});

const allCommits = items.filter(d => d && d.sha && d.commit);
const bCommits = allCommits.filter(c => c.url && c.url.includes('/' + backRepo + '/'));
const fCommits = allCommits.filter(c => c.url && c.url.includes('/' + frontRepo + '/'));

const allPRs = items.filter(d => d && d.number && d.state && d.html_url?.includes('/pull/'));
const bPRs = allPRs.filter(p => p.base?.repo?.name === backRepo);
const fPRs = allPRs.filter(p => p.base?.repo?.name === frontRepo);

const listaById = {};
lists.forEach(l => { listaById[l.id] = l.name; });
const miembroById = {};
members.forEach(m => { miembroById[m.id] = m.fullName || m.username; });

const checklistsByCard = {};
checklists.forEach(ch => {
  if (!checklistsByCard[ch.idCard]) checklistsByCard[ch.idCard] = [];
  checklistsByCard[ch.idCard].push(ch);
});

function normFase(s) {
  return (s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
}

const tareasRaw = cards.map(c => {
  const due = c.due ? new Date(c.due) : null;
  const vencida = due && !c.dueComplete && due < now;
  const diasRestantes = due ? Math.floor((due - now) / 86400000) : null;
  const atts = c.attachments || [];
  const enlaces = atts.filter(a => a.url && a.isUpload === false).map(a => ({ name: a.name || a.url, url: a.url }));
  const archivos = atts.filter(a => a.isUpload === true).map(a => ({ name: a.name, url: a.url, mimeType: a.mimeType || '' }));
  const pdfs = archivos.filter(a => (a.mimeType || '').includes('pdf') || (a.name || '').toLowerCase().endsWith('.pdf'));
  const chArr = checklistsByCard[c.id] || [];
  const chTotal = chArr.reduce((s, ch) => s + (ch.checkItems?.length || 0), 0);
  const chDone = chArr.reduce((s, ch) => s + (ch.checkItems?.filter(i => i.state === 'complete').length || 0), 0);
  const daysSince = c.dateLastActivity ? Math.floor((now - new Date(c.dateLastActivity)) / 86400000) : null;
  const responsables = (c.idMembers || []).map(id => miembroById[id] || id);
  return {
    id: c.id,
    nombre: c.name,
    lista: listaById[c.idList] || 'desconocida',
    completada: !!c.dueComplete,
    fecha_limite: c.due,
    dias_restantes: diasRestantes,
    vencida: !!vencida,
    responsables,
    responsables_ids: c.idMembers || [],
    adjuntos_count: atts.length,
    enlaces,
    archivos,
    pdfs_count: pdfs.length,
    checklist_total: chTotal,
    checklist_done: chDone,
    checklist_pct: chTotal > 0 ? Math.round(chDone / chTotal * 100) : null,
    dias_sin_actividad: daysSince,
    dateLastActivity: c.dateLastActivity,
    stale: daysSince !== null && daysSince > 5 && !c.dueComplete,
    sin_asignar: (c.idMembers || []).length === 0,
    sin_fecha: !c.due
  };
});

const tareas = tareasRaw.filter(t => t.nombre && t.nombre.trim() !== '.');

const fases = {};
for (const t of tareas) {
  const key = normFase(t.lista);
  if (!fases[key]) fases[key] = { nombre: t.lista, tareas: [], completadas: 0, vencidas: 0, pendientes: 0 };
  fases[key].tareas.push(t);
  if (t.completada) fases[key].completadas++;
  else if (t.vencida) fases[key].vencidas++;
  else fases[key].pendientes++;
}
for (const f of Object.values(fases)) {
  f.total = f.tareas.length;
  f.pct = f.total > 0 ? Math.round(f.completadas / f.total * 100) : 0;
  if (f.vencidas > 0) f.semaforo = 'rojo';
  else if (f.pct >= 80) f.semaforo = 'verde';
  else if (f.pct >= 40) f.semaforo = 'amarillo';
  else f.semaforo = 'gris';
}

const vencidas = tareas.filter(t => t.vencida);
const completadas = tareas.filter(t => t.completada);
const pendientes = tareas.filter(t => !t.completada && !t.vencida);
const stales = tareas.filter(t => t.stale);
const sinAsignar = tareas.filter(t => t.sin_asignar);
const sinFecha = tareas.filter(t => t.sin_fecha);
const progreso = tareas.length > 0 ? Math.round(completadas.length / tareas.length * 100) : 0;

const sevenDaysAgo = new Date(now - 7 * 86400000);
const fourteenDaysAgo = new Date(now - 14 * 86400000);
const thirtyDaysAgo = new Date(now - 30 * 86400000);

const completadas7d = completadas.filter(t => t.dateLastActivity && new Date(t.dateLastActivity) >= sevenDaysAgo).length;
const velocidad = (completadas7d / 7).toFixed(2);
const aTiempo = completadas.filter(t => !t.fecha_limite || new Date(t.fecha_limite) >= new Date(t.dateLastActivity || 0)).length;
const pctATiempo = completadas.length > 0 ? Math.round(aTiempo / completadas.length * 100) : 100;

const commitsRecent = [...bCommits, ...fCommits].filter(c => c.commit?.author?.date && new Date(c.commit.author.date) >= fourteenDaysAgo);
const commitsPorDia = (commitsRecent.length / 14).toFixed(2);

const prsAbiertos = [...bPRs, ...fPRs].filter(p => p.state === 'open');
const prOpenTimes = prsAbiertos.map(p => (now - new Date(p.created_at)) / 86400000);
const avgPROpenDays = prOpenTimes.length > 0 ? (prOpenTimes.reduce((a, b) => a + b, 0) / prOpenTimes.length).toFixed(1) : '0';
const prsRecientes = [...bPRs, ...fPRs].filter(p => new Date(p.created_at) >= thirtyDaysAgo);
const mergeados = prsRecientes.filter(p => p.merged_at).length;
const cerrados = prsRecientes.filter(p => p.state === 'closed').length;
const mergeRatio = cerrados > 0 ? Math.round(mergeados / cerrados * 100) : 0;

const convRegex = /^(feat|fix|docs|style|refactor|test|chore|perf|ci|build)(\(.+\))?:/i;
const convCommits = commitsRecent.filter(c => convRegex.test((c.commit?.message || '').split('\n')[0]));
const pctConv = commitsRecent.length > 0 ? Math.round(convCommits.length / commitsRecent.length * 100) : 0;

const authorsRecent = new Set(commitsRecent.map(c => c.author?.login || c.commit?.author?.email || '?').filter(x => x !== '?'));
const busFactor = authorsRecent.size;

const lastBackCommit = bCommits[0]?.commit?.author?.date;
const lastFrontCommit = fCommits[0]?.commit?.author?.date;
const silenceBack = lastBackCommit ? Math.floor((now - new Date(lastBackCommit)) / 86400000) : null;
const silenceFront = lastFrontCommit ? Math.floor((now - new Date(lastFrontCommit)) / 86400000) : null;

const bLastRun = bRuns[0];
const fLastRun = fRuns[0];
const ciBack = bLastRun ? { status: bLastRun.conclusion || bLastRun.status, date: bLastRun.updated_at, name: bLastRun.name, url: bLastRun.html_url, branch: bLastRun.head_branch, actor: bLastRun.actor?.login } : null;
const ciFront = fLastRun ? { status: fLastRun.conclusion || fLastRun.status, date: fLastRun.updated_at, name: fLastRun.name, url: fLastRun.html_url, branch: fLastRun.head_branch, actor: fLastRun.actor?.login } : null;

const hoyStr = now.toISOString().slice(0, 10);
const proximos = hitos.filter(h => h.fecha_fin >= hoyStr && !h.completado).slice(0, 5).map(h => ({
  nombre: h.nombre, tipo: h.tipo, fecha_fin: h.fecha_fin,
  dias_faltan: Math.floor((new Date(h.fecha_fin) - now) / 86400000),
  responsable: h.responsable
}));
const fin = hitos.find(h => h.tipo === 'entrega_final');
const diasHastaFin = fin ? Math.floor((new Date(fin.fecha_fin) - now) / 86400000) : null;

let proyeccion = 'sin datos';
if (diasHastaFin !== null && pendientes.length > 0) {
  const necesaria = pendientes.length / Math.max(diasHastaFin, 1);
  if (parseFloat(velocidad) >= necesaria) proyeccion = 'on-track';
  else if (parseFloat(velocidad) >= necesaria * 0.7) proyeccion = 'riesgo';
  else proyeccion = 'retrasado';
}

const workPerPerson = {};
for (const t of tareas) {
  for (const r of t.responsables) {
    const m = resolveMember(r);
    if (!workPerPerson[r]) workPerPerson[r] = { trello_name: r, initials: m.initials, github: m.github, tareas_total: 0, tareas_done: 0, tareas_pending: 0, tareas_overdue: 0, commits_14d: 0 };
    workPerPerson[r].tareas_total++;
    if (t.completada) workPerPerson[r].tareas_done++;
    else if (t.vencida) workPerPerson[r].tareas_overdue++;
    else workPerPerson[r].tareas_pending++;
  }
}
for (const c of commitsRecent) {
  const login = c.author?.login;
  if (!login) continue;
  for (const p of Object.values(workPerPerson)) {
    if (p.github === login) p.commits_14d++;
  }
}
const ranking = Object.values(workPerPerson).sort((a, b) => (b.tareas_done + b.commits_14d) - (a.tareas_done + a.commits_14d));

let tendencia = 'sin historial suficiente';
if (historial.length >= 3) {
  const conProblemas = historial.filter(h => h.hay_problemas).length;
  tendencia = conProblemas >= 3 ? conProblemas + '/' + historial.length + ' con problemas' : 'estable';
}

let diffPrev = null;
if (historial.length > 0) {
  const prev = historial[0];
  const prevKpis = (typeof prev.kpis_json === 'string' ? JSON.parse(prev.kpis_json) : prev.kpis_json) || {};
  diffPrev = {
    progreso: progreso - (prev.progreso_pct || 0),
    vencidas: vencidas.length - (prev.tareas_vencidas || 0),
    commits_14d: commitsRecent.length - (prevKpis.commits_14d || 0)
  };
}

function formatCommits(list, limit) {
  return list.slice(0, limit).map(c => ({
    sha: (c.sha || '').slice(0, 7),
    autor: c.commit?.author?.name || c.author?.login || '?',
    login: c.author?.login || null,
    mensaje: (c.commit?.message || '').split('\n')[0].slice(0, 120),
    fecha: c.commit?.author?.date,
    url: c.html_url
  }));
}
const topBack = formatCommits(bCommits, 5);
const topFront = formatCommits(fCommits, 5);

const kpis = {
  velocidad_tareas_por_dia: parseFloat(velocidad),
  completadas_7d: completadas7d,
  pct_a_tiempo: pctATiempo,
  progreso_sprint_pct: progreso,
  commits_por_dia: parseFloat(commitsPorDia),
  commits_14d: commitsRecent.length,
  pct_commits_convencionales: pctConv,
  bus_factor_14d: busFactor,
  silencio_back_dias: silenceBack,
  silencio_front_dias: silenceFront,
  pr_open_time_dias: parseFloat(avgPROpenDays),
  pr_merge_ratio_30d: mergeRatio,
  dias_hasta_fin: diasHastaFin,
  proyeccion
};

const problemas = [];
if (vencidas.length > 0) problemas.push({ tipo: 'tareas_vencidas', severidad: 'alta', count: vencidas.length });
if (proyeccion === 'retrasado') problemas.push({ tipo: 'proyeccion_retraso', severidad: 'alta' });
if (proyeccion === 'riesgo') problemas.push({ tipo: 'proyeccion_riesgo', severidad: 'media' });
if (parseFloat(avgPROpenDays) > 7 && prsAbiertos.length > 0) problemas.push({ tipo: 'pr_stale', severidad: 'media', count: prsAbiertos.filter(p => (now - new Date(p.updated_at)) / 86400000 > 7).length });
if (parseFloat(commitsPorDia) < 0.5 && diasHastaFin !== null && diasHastaFin < 45) problemas.push({ tipo: 'baja_actividad', severidad: 'media' });
if (ciBack && ciBack.status === 'failure') problemas.push({ tipo: 'ci_back_roto', severidad: 'alta' });
if (ciFront && ciFront.status === 'failure') problemas.push({ tipo: 'ci_front_roto', severidad: 'alta' });
if (stales.length > 3) problemas.push({ tipo: 'cards_stale', severidad: 'media', count: stales.length });
if (busFactor < 2 && commitsRecent.length > 0 && diasHastaFin !== null && diasHastaFin < 45) problemas.push({ tipo: 'bus_factor_bajo', severidad: 'media' });
if (sinAsignar.length > 0) problemas.push({ tipo: 'cards_sin_asignar', severidad: 'baja', count: sinAsignar.length });

const sev = problemas.map(p => p.severidad);
const severidadMax = sev.includes('alta') ? 'alta' : sev.includes('media') ? 'media' : 'baja';

return [{
  json: {
    fecha: now.toISOString(),
    hay_problemas: problemas.length > 0,
    total_tarjetas: tareas.length,
    total_completadas: completadas.length,
    total_pendientes: pendientes.length,
    tareas_vencidas_list: vencidas,
    tareas_vencidas_count: vencidas.length,
    progreso_pct: progreso,
    fases,
    ranking,
    cards_stale: stales,
    cards_sin_asignar: sinAsignar,
    cards_sin_fecha: sinFecha,
    kpis,
    hitos_proximos: proximos,
    tendencia_historial: tendencia,
    diff_previa: diffPrev,
    problemas_detectados: problemas,
    severidad_max: severidadMax,
    cantidad_problemas: problemas.length,
    github: {
      commits_back: bCommits.length,
      commits_front: fCommits.length,
      prs_abiertos_back: bPRs.filter(p => p.state === 'open').length,
      prs_abiertos_front: fPRs.filter(p => p.state === 'open').length,
      prs_detalle_abiertos: prsAbiertos.map(p => ({ numero: p.number, titulo: p.title, autor: p.user?.login, dias_abierto: Math.floor((now - new Date(p.created_at)) / 86400000), repo: p.base?.repo?.name, url: p.html_url })),
      top_commits_back: topBack,
      top_commits_front: topFront,
      ci_back: ciBack,
      ci_front: ciFront,
      deploy_front_url: 'https://pet-safe-six.vercel.app',
      back_repo_url: 'https://github.com/' + $node['Configuración'].json.GITHUB_OWNER_BACKEND + '/' + backRepo,
      front_repo_url: 'https://github.com/' + $node['Configuración'].json.GITHUB_OWNER_FRONTEND + '/' + frontRepo
    },
    snapshot_tareas: tareas,
    gemini_key: $node['Configuración'].json.GEMINI_API_KEY,
    discord_url: $node['Configuración'].json.DISCORD_WEBHOOK_URL
  }
}];

const analisisId = $json.id;
const snapshot = $node['Análisis + KPIs'].json.snapshot_tareas;

const rows = snapshot.map(t => {
  const memId = (t.responsables_ids || [])[0] || null;
  const memName = (t.responsables || [])[0] || null;
  return {
    analisis_id: analisisId,
    card_id: t.id,
    card_nombre: (t.nombre || '').slice(0, 500),
    lista_nombre: t.lista,
    miembro_id: memId,
    miembro_nombre: memName,
    fecha_vencimiento: t.fecha_limite,
    completada: t.completada,
    tiene_adjuntos: t.adjuntos_count > 0,
    adjuntos_count: t.adjuntos_count
  };
});

return rows.map(r => ({ json: r }));

const d = $node['Análisis + KPIs'].json;

function semEmoji(s) { return ({ verde: '🟢', amarillo: '🟡', rojo: '🔴', gris: '⚪' })[s] || '⚪'; }

function renderFase(f) {
  const lines = [semEmoji(f.semaforo) + ' ' + f.nombre + ' (' + f.completadas + '/' + f.total + ' = ' + f.pct + '%)'];
  for (const t of f.tareas) {
    const status = t.completada ? '[✓]' : (t.vencida ? '[✗ VENCIDA]' : '[⏳]');
    const resp = t.responsables.length > 0 ? t.responsables.join(', ') : 'SIN ASIGNAR';
    const due = t.fecha_limite ? ' due=' + t.fecha_limite.slice(0, 10) : ' (sin fecha)';
    const chk = t.checklist_total > 0 ? ' checklist=' + t.checklist_done + '/' + t.checklist_total : '';
    const adj = t.adjuntos_count > 0 ? ' adj=' + t.adjuntos_count : '';
    lines.push('  ' + status + ' ' + t.nombre + ' -> ' + resp + due + chk + adj);
  }
  return lines.join('\n');
}

const fasesStr = Object.values(d.fases).map(renderFase).join('\n\n');

const commitsBackStr = d.github.top_commits_back.map(c => '  ' + c.sha + ' ' + c.autor + ': ' + c.mensaje + ' (' + (c.fecha || '').slice(0, 10) + ')').join('\n') || '  (sin commits)';
const commitsFrontStr = d.github.top_commits_front.map(c => '  ' + c.sha + ' ' + c.autor + ': ' + c.mensaje + ' (' + (c.fecha || '').slice(0, 10) + ')').join('\n') || '  (sin commits)';

const entregables = d.snapshot_tareas
  .filter(t => (t.archivos.length > 0 || t.enlaces.length > 0) && t.nombre && t.nombre.trim() !== '.')
  .sort((a, b) => new Date(b.dateLastActivity || 0) - new Date(a.dateLastActivity || 0))
  .slice(0, 15)
  .map(t => {
    const files = t.archivos.map(a => a.name).join(', ');
    const links = t.enlaces.map(l => (l.name || l.url)).join(', ');
    const parts = [files, links].filter(Boolean).join(' | ');
    return '  [' + t.lista + '] ' + t.nombre + ': ' + parts;
  }).join('\n') || '  (ninguno)';

const rankingStr = d.ranking.map(r => '  ' + r.initials + ' ' + r.trello_name + ': ' + r.tareas_done + '✓ / ' + r.tareas_pending + '⏳ / ' + r.tareas_overdue + '✗   commits14d=' + r.commits_14d).join('\n') || '  (sin datos)';

const ciBack = d.github.ci_back ? d.github.ci_back.status + ' en ' + d.github.ci_back.branch + ' (' + (d.github.ci_back.date || '').slice(0, 10) + ')' : 'sin datos';
const ciFront = d.github.ci_front ? d.github.ci_front.status + ' en ' + d.github.ci_front.branch + ' (' + (d.github.ci_front.date || '').slice(0, 10) + ')' : 'sin datos';

function sign(n) { return n >= 0 ? '+' + n : String(n); }
const diffStr = d.diff_previa ? 'progreso ' + sign(d.diff_previa.progreso) + '% | vencidas ' + sign(d.diff_previa.vencidas) + ' | commits14d ' + sign(d.diff_previa.commits_14d) : 'sin previa';

const staleStr = d.cards_stale.slice(0, 5).map(t => t.nombre + '(' + t.dias_sin_actividad + 'd, ' + (t.responsables[0] || 'sin asignar') + ')').join(', ') || 'ninguna';
const sinAsignarStr = d.cards_sin_asignar.slice(0, 5).map(t => t.nombre).join(', ') || 'ninguna';
const sinFechaStr = d.cards_sin_fecha.slice(0, 5).map(t => t.nombre).join(', ') || 'ninguna';

const prompt = 'Eres gestor PM del proyecto PetSafe (clínica veterinaria, NestJS backend + Angular frontend, fin programado 2026-06-10). Analiza estado real y da diagnóstico accionable en español, texto plano, SIN markdown, SIN asteriscos, SIN emojis.\n\n' +
'Estructura OBLIGATORIA, cada sección máx 3 oraciones:\n' +
'RESUMEN: estado global (verde/amarillo/rojo) con motivo principal en una línea.\n' +
'POR FASE: comenta SOLO las fases con problemas o riesgo, menciona tareas específicas por nombre.\n' +
'CARGA EQUIPO: observación sobre distribución de trabajo entre FG, DM, DP, JA.\n' +
'RIESGOS: top 3 con severidad y causa (no inventes, usa los datos).\n' +
'ACCIONES: 3 acciones concretas asignadas por nombre real (ej: Josué revisar PR X, David Barragán desbloquear tarea Y).\n' +
'PROYECCION: llegamos al 10-jun-2026? sí/no/riesgo con justificación numérica.\n\n' +
'=== CONTEXTO REAL ===\n' +
'Fecha: ' + d.fecha + '\n' +
'Progreso global: ' + d.progreso_pct + '% (' + d.total_completadas + '/' + d.total_tarjetas + ')\n' +
'Días hasta fin proyecto: ' + d.kpis.dias_hasta_fin + '\n' +
'Proyección calculada: ' + d.kpis.proyeccion + '\n' +
